 dom.timeline.innerHTML=sorted.map(p=>{const g=pos(p,year); return `<div style="display:grid;grid-template-columns:1.2fr 5fr auto;gap:10px;align-items:center;margin-bottom:10px"><div style="font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="${escAttr(p.title)}">${esc(p.title)}</div><div style="position:relative;height:26px;border-radius:999px;background:#eef4fb;border:1px solid #dde7f4;overflow:hidden"><div style="position:absolute;left:${g.left}%;width:${g.width}%;top:2px;height:22px;border-radius:999px;background:linear-gradient(135deg,#1f5fa8,#4f81c4);color:#fff;display:flex;align-items:center;justify-content:center;font-size:.78rem;font-weight:700">${esc(p.status)}</div></div><div class="mini badge">${dday(p.endDate)}</div></div>`}).join('');
